package taskengine

import (
	"strings"
	"testing"

	"github.com/jackc/pgx/v5/pgtype"

	dbgen "github.com/sargunv/tend/server/internal/database/gen"
)

func nullOverdueAction(a dbgen.OverdueAction) dbgen.NullOverdueAction {
	return dbgen.NullOverdueAction{OverdueAction: a, Valid: true}
}

func TestValidateOverdueActionRule(t *testing.T) {
	tests := []struct {
		name           string
		afterDays      pgtype.Int4
		action         dbgen.NullOverdueAction
		statusName     pgtype.Text
		recurrenceType dbgen.RecurrenceType
		hasDue         bool
		wantErr        bool
		errContains    string
	}{
		// ─── No rule ─────────────────────────────────────────────────────────────────
		{
			name:           "nil rule always valid",
			action:         dbgen.NullOverdueAction{Valid: false},
			recurrenceType: dbgen.RecurrenceTypeOneOff,
			hasDue:         false,
			wantErr:        false,
		},
		// ─── Invalid configurations ───────────────────────────────────────────────────
		{
			name:           "rule on one_off task",
			action:         nullOverdueAction(dbgen.OverdueActionAdvanceRecurrence),
			recurrenceType: dbgen.RecurrenceTypeOneOff,
			hasDue:         true,
			wantErr:        true,
			errContains:    "only valid on recurring tasks",
		},
		{
			name:           "rule on on_dependency task",
			action:         nullOverdueAction(dbgen.OverdueActionAdvanceRecurrence),
			recurrenceType: dbgen.RecurrenceTypeOnDependency,
			hasDue:         true,
			wantErr:        true,
			errContains:    "only valid on recurring tasks",
		},
		{
			name:           "rule requires due date",
			action:         nullOverdueAction(dbgen.OverdueActionAdvanceRecurrence),
			recurrenceType: dbgen.RecurrenceTypeCompletionBased,
			hasDue:         false,
			wantErr:        true,
			errContains:    "requires a due date",
		},
		{
			name:           "advance_recurrence on fixed_accumulating",
			action:         nullOverdueAction(dbgen.OverdueActionAdvanceRecurrence),
			recurrenceType: dbgen.RecurrenceTypeFixedAccumulating,
			hasDue:         true,
			wantErr:        true,
			errContains:    "not supported on fixed_accumulating",
		},
		{
			name:           "set_status without status name",
			action:         nullOverdueAction(dbgen.OverdueActionSetStatus),
			statusName:     pgtype.Text{Valid: false},
			recurrenceType: dbgen.RecurrenceTypeCompletionBased,
			hasDue:         true,
			wantErr:        true,
			errContains:    "status is required",
		},
	}

	for _, tc := range tests {
		t.Run(tc.name, func(t *testing.T) {
			err := ValidateOverdueActionRule(tc.afterDays, tc.action, tc.statusName, tc.recurrenceType, tc.hasDue)
			if tc.wantErr {
				if err == nil {
					t.Fatal("expected error, got nil")
				}
				if tc.errContains != "" && !strings.Contains(err.Error(), tc.errContains) {
					t.Errorf("error %q does not contain %q", err.Error(), tc.errContains)
				}
			} else if err != nil {
				t.Fatalf("unexpected error: %v", err)
			}
		})
	}
}

package api_test

import (
	"fmt"
	"net/http"
	"testing"
	"time"

	"github.com/sargunv/tend/server/internal/taskengine"
)

// ─── Handler tests ────────────────────────────────────────────────────────────

func TestOverdueActionCreateWithAdvanceRecurrence(t *testing.T) {
	env := setupTestServer(t)
	createSpace(t, env, "home", "Home")

	future := time.Now().AddDate(0, 0, 30).Format("2006-01-02")
	task := createTask(t, env, "home", fmt.Sprintf(
		`{"title":"Weekly","recurrenceType":"completion_based","recurrenceRule":"RRULE:FREQ=WEEKLY","due":{"at":%q,"timezone":"UTC"},"overdueActionRule":{"after":null,"action":"advance_recurrence"}}`,
		future,
	))

	rule, ok := task["overdueActionRule"].(map[string]any)
	if !ok {
		t.Fatalf("overdueActionRule missing or wrong type: %T", task["overdueActionRule"])
	}
	if rule["action"] != "advance_recurrence" {
		t.Errorf("action = %v, want advance_recurrence", rule["action"])
	}
	if rule["after"] != nil {
		t.Errorf("after = %v, want nil", rule["after"])
	}
}

func TestOverdueActionCreateWithSetStatus(t *testing.T) {
	env := setupTestServer(t)
	createSpace(t, env, "home", "Home")

	future := time.Now().AddDate(0, 0, 30).Format("2006-01-02")
	task := createTask(t, env, "home", fmt.Sprintf(
		`{"title":"Weekly","recurrenceType":"completion_based","recurrenceRule":"RRULE:FREQ=WEEKLY","due":{"at":%q,"timezone":"UTC"},"overdueActionRule":{"after":3,"action":"set_status","status":"done"}}`,
		future,
	))

	rule, ok := task["overdueActionRule"].(map[string]any)
	if !ok {
		t.Fatalf("overdueActionRule missing or wrong type: %T", task["overdueActionRule"])
	}
	if rule["action"] != "set_status" {
		t.Errorf("action = %v, want set_status", rule["action"])
	}
	after := jsonAs[float64](t, rule["after"])
	if after != 3 {
		t.Errorf("after = %v, want 3", after)
	}
	if rule["status"] != "done" {
		t.Errorf("status = %v, want done", rule["status"])
	}
}

